import { mkdir } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { build } from 'esbuild';

const outfile = resolve('packages/frontend/public/lintic-mock-pg.js');
const objectHashShim = resolve('scripts/shims/object-hash-browser.js');

await mkdir(dirname(outfile), { recursive: true });

await build({
  entryPoints: [resolve('packages/mock-pg/src/index.ts')],
  outfile,
  bundle: true,
  format: 'esm',
  platform: 'node',
  target: 'node20',
  sourcemap: false,
  banner: {
    js: '// Generated by scripts/build-mock-pg-webcontainer-bundle.mjs',
  },
  plugins: [
    {
      name: 'lintic-mock-pg-browser-shims',
      setup(buildContext) {
        buildContext.onResolve({ filter: /^object-hash$/ }, () => ({
          path: objectHashShim,
        }));
      },
    },
  ],
});
